class ApothecaryGeneral:
    def __init__(self, name):
        self.name = name
        self.medicines = {}

    def report_supply(self, medicine_name, quantity):
        self.medicines[medicine_name] = quantity

    def submit_bill(self, treasury, secretary_at_war_approval):
        if not secretary_at_war_approval:
            raise ValueError("Bill not approved by Secretary at War")
        return {
            "apothecary": self.name,
            "medicines": self.medicines,
            "status": "Submitted to Treasury"
        }

# Example usage
apothecary = ApothecaryGeneral("George Garnier")
apothecary.report_supply("Opium", 500)
apothecary.report_supply("Quinine", 300)
bill = apothecary.submit_bill("Treasury", True)
print(bill)

This code simulates the process where the Apothecary General submits a semi-annual bill to the Treasury after obtaining necessary approvals.
